/// Binary-search lookup of an element's covalent radius.
pub fn r_cov(symbol: &str) -> Option<f64> {
    R_COV.binary_search_by(|(s, _)| (*s).cmp(symbol)).ok().map(|k| R_COV[k].1)
}
